const res = await fetch('https://neverparse.com/api/v1/infer/detect', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ data: { name: 'Alice', age: 30, active: true } })
});
const { schema } = await res.json();

const res = await fetch('https://neverparse.com/api/v1/errormap/parse', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    raw: { error: { code: 'RATE_LIMIT_EXCEEDED', message: 'Too many requests' } },
    statusCode: 429,
    headers: { 'Retry-After': '30' }
  })
});
const { problem } = await res.json();
if (problem.retryable) await sleep(problem.retryAfterMs);

const res = await fetch('https://neverparse.com/api/v1/toolbridge/convert', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    tool: { type: 'function', function: { name: 'get_weather', description: 'Get weather', parameters: { type: 'object', properties: { location: { type: 'string' } }, required: ['location'] } } },
    from: 'openai',
    to: 'anthropic'
  })
});
const { result } = await res.json();
